import styled from "styled-components"

import brandIcon from '../img/LandingPage/brandLogo.svg'

const LandingPage = () => {
  return (
    <Container>
      <Brand>
        <img src={brandIcon} alt="brandIcon" />
        <span> Adam Jałocha </span>
        <span> Web developer </span>
      </Brand>
      <Introduction> 
        <Name> Adam Jałocha </Name>
        <hr />
        <Description>
          I am a front-end developer who use react to accomplish goals.
        </Description>
      </Introduction>
      <More> More </More>

      <QuickContact> QuickContact </QuickContact>
    </Container>
  )
}

const Container = styled.section`
  width: 100vw;
  height: 100vh;
  background: black;
  color: white;

  display: grid;
  grid-template: auto 1fr auto / auto auto;
  align-items: center;
  justify-content: space-between;

  font-family: Rubik;

  & > * {
    padding: 1em 5em;
  }
`

const Brand = styled.span`
  display: grid;
  grid-template: 1fr 1fr / auto 1fr;
  column-gap: 0.5em;
  align-items: center;

  & img {
    grid-column: 1;
    grid-row: 1/3;
    height: 100%;
    width: auto;
    border-radius: 4px;
    box-shadow: 0px 0px 1px white;
    filter: invert(0.9)
  }

  & span {
    font-weight: 400;
    font-size: 0.8em;
  }
`

const Introduction = styled.div`
  font-size: 3em;
  padding: 0 0 0em 3em;

  position: relative;
  display: flex;
  flex-direction: column;
  row-gap: 1em;

  & > hr {
    position: absolute;
    width: 120%;
    left: 0;
    top: 1em;
  }
`

const Name = styled.span`
  font-weight: 600;
`

const Description = styled.span`
  font-size: 0.3em;
  font-weight: 100;
  width: 35ch;
`

const More = styled.span``
const QuickContact = styled.div`
  grid-column: 2;
  grid-row: 1/4;
`

export default LandingPage
